  ('dietitian-moex-00174', 'dietitian', 'dietitian-moex-114-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '有關五碳糖磷酸途徑（pentose phosphate pathway）調節之敘述，下列何者正確？', '["malic enzyme催化之反應是此途徑關鍵調節點", "受調節之關鍵酵素表現於粒線體內", "+ [NADP ]／[NADPH] 比值上升時，會異位活化其關鍵調節酵素", "+ 當[NAD ]下降時，會使五碳糖磷酸途徑的反應速率下降"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:49+00:00", "source_pdf_sha1": "c8c7112f23f9", "answer_pdf_sha1": "925f56d717e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
